Bash(node -e "
const { loadConfig, saveConfig } = require\('./dist/config.js'\);
const { readCache, writeCache } = require\('./dist/cache.js'\);

const config = loadConfig\(\);
const cache = readCache\(\);

const weeklyTokens = cache.weekly.tokens.inputTokens + cache.weekly.tokens.outputTokens;
const webPct = 30;
const factor = webPct / weeklyTokens;

console.log\('Weekly tokens:', weeklyTokens.toLocaleString\(\)\);
console.log\('Web usage %:', webPct\);
console.log\('Factor:', factor.toExponential\(6\)\);

config.calibration.dataPoints.push\({
  date: new Date\(\).toISOString\(\),
  tokens: weeklyTokens,
  webUsagePct: webPct,
}\);
config.calibration.factor = factor;
config.calibration.lastCalibrated = new Date\(\).toISOString\(\);
saveConfig\(config\);

// Update cache with factor
cache.calibrationFactor = factor;
writeCache\(cache\);

console.log\('Done — calibration saved'\);
")

